import React, { useState } from 'react';
import { Layout } from './components/Layout';
import { OnboardingScreen } from './screens/OnboardingScreen';
import { AssessmentScreen } from './screens/AssessmentScreen';
import { PathScreen } from './screens/PathScreen';
import { StepDetailScreen } from './screens/StepDetailScreen';
import { ScreenName, UserProfile } from './types';
import { PATH_STEPS } from './data';

const App: React.FC = () => {
  const [currentScreen, setCurrentScreen] = useState<ScreenName>(ScreenName.ONBOARDING);
  const [userProfile, setUserProfile] = useState<UserProfile>({
    currentRole: '',
    targetRole: '',
    experienceYears: 0
  });
  const [selectedStepId, setSelectedStepId] = useState<string | null>(null);

  const handleOnboardingComplete = (profile: UserProfile) => {
    setUserProfile(profile);
    setCurrentScreen(ScreenName.ASSESSMENT);
  };

  const handleAssessmentComplete = () => {
    setCurrentScreen(ScreenName.PATH);
  };

  const handleStepClick = (stepId: string) => {
    setSelectedStepId(stepId);
    setCurrentScreen(ScreenName.DETAIL);
  };

  const renderScreen = () => {
    switch (currentScreen) {
      case ScreenName.ONBOARDING:
        return <OnboardingScreen onNext={handleOnboardingComplete} />;
      case ScreenName.ASSESSMENT:
        return (
          <AssessmentScreen 
            userProfile={userProfile} 
            onNext={handleAssessmentComplete} 
            onBack={() => setCurrentScreen(ScreenName.ONBOARDING)}
          />
        );
      case ScreenName.PATH:
        return (
          <PathScreen 
            onStepClick={handleStepClick} 
            onBack={() => setCurrentScreen(ScreenName.ASSESSMENT)}
          />
        );
      case ScreenName.DETAIL:
        const step = PATH_STEPS.find(s => s.id === selectedStepId);
        if (!step) return null;
        return (
          <StepDetailScreen 
            step={step} 
            onBack={() => setCurrentScreen(ScreenName.PATH)} 
          />
        );
      default:
        return <OnboardingScreen onNext={handleOnboardingComplete} />;
    }
  };

  return (
    <Layout>
      {renderScreen()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { Icon } from './Icon';

interface DebugOverlayProps {
  currentVersion: string;
  onVersionChange: (version: string) => void;
}

export const DebugOverlay: React.FC<DebugOverlayProps> = ({ currentVersion, onVersionChange }) => {
  const [isOpen, setIsOpen] = useState(false);

  const versions = [
    { id: 'v1', label: 'Classic Route' },
    { id: 'v2', label: 'Subway Map' },
    { id: 'v3', label: 'Focus Cards' }
  ];

  return (
    <div className="fixed bottom-20 right-4 z-50 flex flex-col items-end gap-2">
      {isOpen && (
        <div className="bg-slate-900 text-white rounded-xl shadow-2xl overflow-hidden min-w-[160px] animate-slide-up origin-bottom-right mb-2">
          <div className="px-4 py-2 bg-slate-800 text-xs font-bold uppercase tracking-wider text-slate-400 border-b border-slate-700">
            UI Version
          </div>
          {versions.map((v) => (
            <button
              key={v.id}
              onClick={() => {
                onVersionChange(v.id);
                setIsOpen(false);
              }}
              className={`w-full text-left px-4 py-3 text-sm font-medium transition-colors flex items-center justify-between ${
                currentVersion === v.id 
                  ? 'bg-primary text-white' 
                  : 'hover:bg-slate-800 text-slate-200'
              }`}
            >
              {v.label}
              {currentVersion === v.id && <Icon name="check" className="text-[16px]" />}
            </button>
          ))}
        </div>
      )}

      <button
        onClick={() => setIsOpen(!isOpen)}
        className={`size-12 rounded-full shadow-lg shadow-slate-900/20 flex items-center justify-center transition-all active:scale-90 ${
          isOpen ? 'bg-slate-900 text-white rotate-90' : 'bg-white text-slate-900 hover:bg-slate-50'
        }`}
      >
        <Icon name={isOpen ? 'close' : 'tune'} />
      </button>
    </div>
  );
};

import React, { useState } from 'react';
import { Layout } from './components/Layout';
import { OnboardingScreen } from './screens/OnboardingScreen';
import { AssessmentScreen } from './screens/AssessmentScreen';
import { PathScreen } from './screens/PathScreen';
import { StepDetailScreen } from './screens/StepDetailScreen';
import { ScreenName, UserProfile } from './types';
import { PATH_STEPS } from './data';
import { DebugOverlay } from './components/DebugOverlay';

const App: React.FC = () => {
  const [currentScreen, setCurrentScreen] = useState<ScreenName>(ScreenName.ONBOARDING);
  const [userProfile, setUserProfile] = useState<UserProfile>({
    currentRole: '',
    targetRole: '',
    experienceYears: 0
  });
  const [selectedStepId, setSelectedStepId] = useState<string | null>(null);

  // UI Version State (Default to 'v1')
  const [uiVersion, setUiVersion] = useState<string>('v1');

  const handleOnboardingComplete = (profile: UserProfile) => {
    setUserProfile(profile);
    setCurrentScreen(ScreenName.ASSESSMENT);
  };

  const handleAssessmentComplete = () => {
    setCurrentScreen(ScreenName.PATH);
  };

  const handleStepClick = (stepId: string) => {
    setSelectedStepId(stepId);
    setCurrentScreen(ScreenName.DETAIL);
  };

  const renderScreen = () => {
    switch (currentScreen) {
      case ScreenName.ONBOARDING:
        return <OnboardingScreen onNext={handleOnboardingComplete} />;
      case ScreenName.ASSESSMENT:
        return (
          <AssessmentScreen 
            userProfile={userProfile} 
            onNext={handleAssessmentComplete} 
            onBack={() => setCurrentScreen(ScreenName.ONBOARDING)}
          />
        );
      case ScreenName.PATH:
        return (
          <PathScreen 
            uiVersion={uiVersion}
            onStepClick={handleStepClick} 
            onBack={() => setCurrentScreen(ScreenName.ASSESSMENT)}
          />
        );
      case ScreenName.DETAIL:
        const step = PATH_STEPS.find(s => s.id === selectedStepId);
        if (!step) return null;
        return (
          <StepDetailScreen 
            step={step} 
            onBack={() => setCurrentScreen(ScreenName.PATH)} 
          />
        );
      default:
        return <OnboardingScreen onNext={handleOnboardingComplete} />;
    }
  };

  return (
    <Layout>
      {renderScreen()}
      {/* Overlay is only useful on the Path screen for this demo, 
          but showing it globally allows context switching anywhere if we expanded support */}
      {currentScreen === ScreenName.PATH && (
        <DebugOverlay 
          currentVersion={uiVersion} 
          onVersionChange={setUiVersion} 
        />
      )}
    </Layout>
  );
};

export default App;

