// --- V1: Classic Layout ---
const ClassicLayout = ({ steps, onStepClick }: { steps: PathStep[], onStepClick: (id: string) => void }) => (
  <div className="relative pl-4 pr-1 animate-fade-in">
    {/* Timeline Line */}
    <div className="absolute left-[22px] top-0 bottom-0 w-[2px] h-full bg-slate-200 z-0"></div>
    {/* Active Line Segment - approximated for mock */}
    <div className="absolute left-[22px] top-0 h-[30%] w-[2px] bg-primary z-0"></div>

    {steps.map((step, index) => {
      const isCurrent = step.status === 'current';
      const isLocked = step.status === 'locked';

      return (
        <div 
          key={step.id} 
          className="relative z-10 grid grid-cols-[48px_1fr] gap-x-4 mb-8 group animate-slide-up"
          style={{ animationDelay: `${200 + (index * 100)}ms` }}
          onClick={() => !isLocked && onStepClick(step.id)}
        >
          {/* Icon Column */}
          <div className="flex flex-col items-center">
            <div className={`
              flex items-center justify-center size-12 rounded-full z-10 border-4 border-[#f6f6f8]
              ${isCurrent ? 'bg-primary text-white shadow-glow scale-110' : ''}
              ${isLocked ? 'bg-white text-slate-300 border-slate-200' : ''}
              ${!isCurrent && !isLocked ? 'bg-blue-600 text-white' : ''}
              transition-all duration-300
            `}>
              <Icon name={isLocked ? "lock" : isCurrent ? "navigation" : "check"} className={isCurrent ? "animate-pulse" : ""} />
            </div>
          </div>

          {/* Content Column */}
          <div className={`flex flex-col pt-1 pb-2 ${isLocked ? 'opacity-60 grayscale' : 'cursor-pointer hover:scale-[1.01] transition-transform'}`}>
            <div className={`
              bg-white rounded-2xl p-5 shadow-soft border relative overflow-hidden
              ${isCurrent ? 'border-primary/20 ring-1 ring-primary/5' : 'border-white'}
            `}>
              {isCurrent && (
                <div className="absolute -top-3 right-4 bg-primary text-white text-[10px] font-bold px-3 py-1.5 rounded-full uppercase tracking-wider shadow-sm">
                  Current Step
                </div>
              )}

              <h3 className="text-slate-900 text-lg font-bold leading-tight mb-1">{step.title}</h3>
              <p className="text-slate-500 text-xs font-semibold uppercase tracking-wide mb-3">{step.subtitle}</p>

              {/* Chips */}
              <div className="flex gap-2 flex-wrap mb-4">
                {step.isGap && (
                    <div className="flex items-center gap-1.5 bg-red-50 px-2 py-1 rounded-md border border-red-100">
                      <span className="text-[10px] font-bold text-red-600 uppercase">Gap</span>
                    </div>
                )}
                  <div className="flex items-center gap-1.5 bg-slate-50 px-2 py-1 rounded-md border border-slate-100">
                    <Icon name="schedule" className="text-[14px] text-slate-400" />
                    <span className="text-[10px] font-bold text-slate-500">{step.effort}</span>
                  </div>
              </div>

              {isCurrent && (
                <div className="w-full flex items-center justify-center gap-2 bg-primary hover:bg-blue-700 active:bg-blue-800 transition-colors rounded-xl h-12 px-4 text-white text-sm font-bold shadow-lg shadow-blue-500/20 mt-2">
                  <span>Start Learning</span>
                  <Icon name="arrow_forward" className="text-[18px]" />
                </div>
              )}
            </div>
          </div>
        </div>
      );
    })}

    {/* End Cap */}
    <div className="absolute left-[18px] bottom-0 w-3 h-3 rounded-full bg-slate-300"></div>
  </div>
);

// --- V2: Subway Layout ---
const SubwayLayout = ({ steps, onStepClick }: { steps: PathStep[], onStepClick: (id: string) => void }) => (
  <div className="relative pt-4 pb-8 animate-fade-in">
    {/* Center Line */}
    <div className="absolute left-1/2 top-0 bottom-0 w-1 bg-slate-200 -translate-x-1/2 rounded-full"></div>

    {steps.map((step, index) => {
      const isEven = index % 2 === 0;
      const isCurrent = step.status === 'current';
      const isLocked = step.status === 'locked';

      return (
        <div key={step.id} className="relative mb-8 grid grid-cols-2 gap-8 items-center"
             onClick={() => !isLocked && onStepClick(step.id)}>

           {/* Center Node */}
           <div className={`
             absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 size-5 rounded-full z-20 border-4 border-[#f6f6f8]
             ${isCurrent ? 'bg-primary scale-125 ring-4 ring-primary/20' : isLocked ? 'bg-slate-300' : 'bg-blue-600'}
             transition-all
           `}></div>

           {/* Left Content */}
           <div className={`${!isEven ? 'col-start-1 text-right pr-2' : 'col-start-2 pl-2 order-2'}`}>
             <div className={`
               p-4 bg-white rounded-2xl shadow-soft border transition-transform
               ${isLocked ? 'opacity-60 grayscale' : 'hover:scale-[1.02] cursor-pointer'}
               ${isCurrent ? 'border-primary ring-2 ring-primary/5' : 'border-slate-100'}
             `}>
               <h3 className="font-bold text-sm text-slate-900 leading-tight">{step.title}</h3>
               <p className="text-[10px] text-slate-500 font-medium mt-1">{step.effort}</p>
               {isCurrent && <div className="mt-2 text-[10px] font-bold text-primary uppercase tracking-wider">Current</div>}
             </div>
           </div>

           {/* Empty side for balance */}
           <div className={!isEven ? 'col-start-2' : 'col-start-1'}></div>
        </div>
      )
    })}
  </div>
);

// --- V3: Focus Cards Layout ---
