import React, { useState } from 'react';
import { Layout } from './components/Layout';
import { OnboardingScreen } from './screens/OnboardingScreen';
import { AssessmentScreen } from './screens/AssessmentScreen';
import { PathScreen } from './screens/PathScreen';
import { StepDetailScreen } from './screens/StepDetailScreen';
import { ScreenName, UserProfile } from './types';
import { PATH_STEPS } from './data';
import { DebugOverlay } from './components/DebugOverlay';

const App: React.FC = () => {
  const [currentScreen, setCurrentScreen] = useState<ScreenName>(ScreenName.ONBOARDING);
  const [userProfile, setUserProfile] = useState<UserProfile>({
    currentRole: '',
    targetRole: '',
    experienceYears: 0
  });
  const [selectedStepId, setSelectedStepId] = useState<string | null>(null);

  // UI Version State (Default to 'v1')
  const [uiVersion, setUiVersion] = useState<string>('v1');

  const handleOnboardingComplete = (profile: UserProfile) => {
    setUserProfile(profile);
    setCurrentScreen(ScreenName.ASSESSMENT);
  };

  const handleAssessmentComplete = () => {
    setCurrentScreen(ScreenName.PATH);
  };

  const handleStepClick = (stepId: string) => {
    setSelectedStepId(stepId);
    setCurrentScreen(ScreenName.DETAIL);
  };

  const renderScreen = () => {
    switch (currentScreen) {
      case ScreenName.ONBOARDING:
        return <OnboardingScreen onNext={handleOnboardingComplete} />;
      case ScreenName.ASSESSMENT:
        return (
          <AssessmentScreen 
            userProfile={userProfile} 
            onNext={handleAssessmentComplete} 
            onBack={() => setCurrentScreen(ScreenName.ONBOARDING)}
          />
        );
      case ScreenName.PATH:
        return (
          <PathScreen 
            uiVersion={uiVersion}
            onStepClick={handleStepClick} 
            onBack={() => setCurrentScreen(ScreenName.ASSESSMENT)}
          />
        );
      case ScreenName.DETAIL:
        const step = PATH_STEPS.find(s => s.id === selectedStepId);
        if (!step) return null;
        return (
          <StepDetailScreen 
            step={step} 
            onBack={() => setCurrentScreen(ScreenName.PATH)} 
          />
        );
      default:
        return <OnboardingScreen onNext={handleOnboardingComplete} />;
    }
  };

  return (
    <Layout>
      {renderScreen()}
      {/* Show overlay on Path screen or if developer wants to force switch (always visible for now to debug 'cannot see' issue) */}
      {(currentScreen === ScreenName.PATH || true) && (
        <DebugOverlay 
          currentVersion={uiVersion} 
          onVersionChange={setUiVersion} 
        />
      )}
    </Layout>
  );
};

export default App;

export enum ScreenName {
  ONBOARDING = 'ONBOARDING',
  ASSESSMENT = 'ASSESSMENT',
  HOME = 'HOME',
  PATH = 'PATH', // Current Progress
  LEARN = 'LEARN',
  PROFILE = 'PROFILE',
  DETAIL = 'DETAIL'
}

export type Theme = 'light' | 'dark' | 'minimal';

export interface UserProfile {
  currentRole: string;
  targetRole: string;
  experienceYears: number;
}

export enum SkillStatus {
  TRANSFERABLE = 'TRANSFERABLE',
  GAP = 'GAP'
}

export enum SkillLevel {
  NONE = 'None',
  BASIC = 'Basic',
  EXPERT = 'Expert'
}

export interface Skill {
  id: string;
  name: string;
  description: string;
  status: SkillStatus;
  level: SkillLevel;
  isTransferable: boolean;
}

export interface PathStep {
  id: string;
  title: string;
  subtitle: string;
  description: string;
  status: 'completed' | 'current' | 'locked';
  effort: string;
  isGap: boolean;
  resources: Resource[];
  proof?: Proof;
}

export interface Resource {
  type: 'VIDEO' | 'ARTICLE' | 'TEMPLATE';
  title: string;
  author?: string;
  url: string;
}

export interface Proof {
  authorName: string;
  authorRole: string;
  authorCompany: string;
  authorImage: string;
  quote: string;
}

import React from 'react';
import { Theme } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  className?: string;
  theme?: Theme;
}

export const Layout: React.FC<LayoutProps> = ({ children, className = "", theme = 'light' }) => {
  const getThemeClasses = () => {
    switch (theme) {
      case 'dark':
        return 'dark bg-slate-950 text-white';
      case 'minimal':
        return 'bg-white text-black grayscale';
      default:
        return 'bg-[#f6f6f8] text-slate-900';
    }
  };

  const getContainerClasses = () => {
     switch (theme) {
      case 'dark':
        return 'bg-slate-900 border-slate-800';
      case 'minimal':
        return 'bg-white border-black';
      default:
        return 'bg-white';
    }
  };

  return (
    <div className={`min-h-screen w-full flex justify-center font-sans transition-colors duration-300 ${getThemeClasses()}`}>
      <div className={`w-full max-w-md min-h-screen shadow-2xl relative flex flex-col transition-colors duration-300 ${getContainerClasses()} ${className}`}>
        {children}
      </div>
    </div>
  );
};

