import { Icon } from './Icon';
import { ScreenName, Theme } from '../types';

interface BottomNavProps {
  currentScreen: ScreenName;
  onNavigate: (screen: ScreenName) => void;
  theme: Theme;
}

export const BottomNav: React.FC<BottomNavProps> = ({ currentScreen, onNavigate, theme }) => {

  const navItems = [
    { id: ScreenName.HOME, icon: 'home', label: 'Home' },
    { id: ScreenName.PATH, icon: 'map', label: 'Progress' },
    { id: ScreenName.LEARN, icon: 'school', label: 'Learn' },
    { id: ScreenName.PROFILE, icon: 'person', label: 'Profile' },
  ];

  const isDark = theme === 'dark';
  const isMinimal = theme === 'minimal';

  return (
    <div className={`fixed bottom-0 left-0 right-0 max-w-md mx-auto z-40 flex justify-around items-center h-20 pb-4 border-t transition-colors duration-300
      ${isDark ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}
      ${isMinimal ? 'bg-white border-t-2 border-black' : ''}
    `}>
      {navItems.map((item) => {
        const isActive = currentScreen === item.id;

        let activeColor = 'text-primary';
        if (isDark) activeColor = 'text-blue-400';
        if (isMinimal) activeColor = 'text-black';

        let inactiveColor = 'text-slate-400';
        if (isDark) inactiveColor = 'text-slate-600';
        if (isMinimal) inactiveColor = 'text-gray-400';

        return (
          <button 
            key={item.id}
            onClick={() => onNavigate(item.id)}
            className={`flex flex-col items-center gap-1 w-16 transition-colors ${isActive ? activeColor : inactiveColor}`}
          >
            <Icon 
              name={item.icon} 
              fill={isActive && !isMinimal} 
              className={`text-[26px] transition-transform duration-200 ${isActive ? 'scale-110' : ''}`}
            />
            <span className="text-[10px] font-bold tracking-wide">{item.label}</span>

            {/* Active Indicator Dot */}
            <div className={`size-1 rounded-full mt-0.5 transition-all duration-300 ${isActive ? (isMinimal ? 'bg-black' : 'bg-current') : 'bg-transparent scale-0'}`}></div>
          </button>
        );
      })}
    </div>
  );
};

import React, { useState } from 'react';
import { Icon } from './Icon';
import { Theme } from '../types';

interface DebugOverlayProps {
  currentVersion: string;
  onVersionChange: (version: string) => void;
  currentTheme: Theme;
  onThemeChange: (theme: Theme) => void;
}

export const DebugOverlay: React.FC<DebugOverlayProps> = ({ 
  currentVersion, 
  onVersionChange,
  currentTheme,
  onThemeChange
}) => {
  const [isOpen, setIsOpen] = useState(false);

  const layouts = [
    { id: 'v1', label: 'Classic Route' },
    { id: 'v2', label: 'Subway Map' },
    { id: 'v3', label: 'Focus Cards' }
  ];

  const themes: { id: Theme; label: string; icon: string }[] = [
    { id: 'light', label: 'Light', icon: 'light_mode' },
    { id: 'dark', label: 'Dark', icon: 'dark_mode' },
    { id: 'minimal', label: 'Minimal', icon: 'contrast' }
  ];

  return (
    <div className="absolute bottom-24 right-4 z-[100] flex flex-col items-end gap-2 pointer-events-none">
      <div className="pointer-events-auto flex flex-col items-end gap-2">
        {isOpen && (
          <div className="bg-slate-900 text-white rounded-2xl shadow-2xl overflow-hidden min-w-[200px] animate-slide-up origin-bottom-right mb-2 border border-slate-800">

            {/* Theme Section */}
            <div className="px-4 py-2 bg-slate-800 text-[10px] font-bold uppercase tracking-wider text-slate-400 border-b border-slate-700">
              App Style
            </div>
            <div className="flex p-2 gap-1 bg-slate-900">
              {themes.map((t) => (
                <button
                  key={t.id}
                  onClick={() => onThemeChange(t.id)}
                  className={`flex-1 flex flex-col items-center justify-center py-2 rounded-lg transition-all ${
                    currentTheme === t.id 
                      ? 'bg-slate-700 text-white shadow-inner' 
                      : 'text-slate-500 hover:text-slate-300 hover:bg-slate-800'
                  }`}
                >
                  <Icon name={t.icon} className="text-[20px] mb-1" />
                  <span className="text-[10px] font-medium">{t.label}</span>
                </button>
              ))}
            </div>

            {/* Layout Section */}
            <div className="px-4 py-2 bg-slate-800 text-[10px] font-bold uppercase tracking-wider text-slate-400 border-b border-slate-700 border-t">
              Route Layout
            </div>
            <div className="flex flex-col">
              {layouts.map((v) => (
                <button
                  key={v.id}
                  onClick={() => onVersionChange(v.id)}
                  className={`w-full text-left px-4 py-3 text-xs font-bold transition-colors flex items-center justify-between ${
                    currentVersion === v.id 
                      ? 'bg-primary text-white' 
                      : 'hover:bg-slate-800 text-slate-400'
                  }`}
                >
                  {v.label}
                  {currentVersion === v.id && <Icon name="check" className="text-[16px]" />}
                </button>
              ))}
            </div>
          </div>
        )}

        <button
          onClick={() => setIsOpen(!isOpen)}
          className={`size-12 rounded-full shadow-lg flex items-center justify-center transition-all active:scale-90 border-2 ${
            isOpen 
              ? 'bg-slate-900 text-white border-slate-900 rotate-90' 
              : 'bg-white text-slate-900 border-slate-100 hover:border-primary/50'
          }`}
        >
          <Icon name={isOpen ? 'close' : 'palette'} />
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Layout } from './components/Layout';
import { BottomNav } from './components/BottomNav';
import { OnboardingScreen } from './screens/OnboardingScreen';
import { AssessmentScreen } from './screens/AssessmentScreen';
import { PathScreen } from './screens/PathScreen';
import { StepDetailScreen } from './screens/StepDetailScreen';
import { ScreenName, UserProfile, Theme } from './types';
import { PATH_STEPS } from './data';
import { DebugOverlay } from './components/DebugOverlay';
import { Icon } from './components/Icon';

// --- Placeholder Screens for Demo ---
const PlaceholderScreen = ({ title, icon, theme }: { title: string, icon: string, theme: Theme }) => (
  <div className="flex-1 flex flex-col items-center justify-center p-8 text-center animate-fade-in pb-24">
    <div className={`size-24 rounded-3xl flex items-center justify-center mb-6 shadow-glow ${
      theme === 'dark' ? 'bg-slate-800 text-blue-400' : 'bg-white text-primary'
    }`}>
      <Icon name={icon} className="text-[48px]" />
    </div>
    <h1 className={`text-2xl font-bold mb-2 ${theme === 'dark' ? 'text-white' : 'text-slate-900'}`}>{title}</h1>
    <p className={`text-sm ${theme === 'dark' ? 'text-slate-400' : 'text-slate-500'}`}>
      This feature is coming soon. Focus on your Career Path for now!
    </p>
  </div>
);

const App: React.FC = () => {
  const [currentScreen, setCurrentScreen] = useState<ScreenName>(ScreenName.ONBOARDING);
  // Separate state to track which main tab is active, to restore it when coming back from detail
  const [activeTab, setActiveTab] = useState<ScreenName>(ScreenName.PATH);

  const [userProfile, setUserProfile] = useState<UserProfile>({
    currentRole: '',
    targetRole: '',
    experienceYears: 0
  });
  const [selectedStepId, setSelectedStepId] = useState<string | null>(null);

  // UI States
  const [uiVersion, setUiVersion] = useState<string>('v1');
  const [theme, setTheme] = useState<Theme>('light');

  const handleOnboardingComplete = (profile: UserProfile) => {
    setUserProfile(profile);
    setCurrentScreen(ScreenName.ASSESSMENT);
  };

  const handleAssessmentComplete = () => {
    setCurrentScreen(ScreenName.PATH);
    setActiveTab(ScreenName.PATH);
  };

  const handleStepClick = (stepId: string) => {
    setSelectedStepId(stepId);
    setCurrentScreen(ScreenName.DETAIL);
  };

  const handleNav = (screen: ScreenName) => {
    setCurrentScreen(screen);
    setActiveTab(screen);
  };

  const renderScreen = () => {
    switch (currentScreen) {
      case ScreenName.ONBOARDING:
        return <OnboardingScreen onNext={handleOnboardingComplete} />;
      case ScreenName.ASSESSMENT:
        return (
          <AssessmentScreen 
            userProfile={userProfile} 
            onNext={handleAssessmentComplete} 
            onBack={() => setCurrentScreen(ScreenName.ONBOARDING)}
          />
        );

      // Main Tabs
      case ScreenName.HOME:
        return <PlaceholderScreen title="Dashboard" icon="dashboard" theme={theme} />;
      case ScreenName.PATH:
        return (
          <PathScreen 
            uiVersion={uiVersion}
            theme={theme}
            onStepClick={handleStepClick} 
            onBack={() => setCurrentScreen(ScreenName.ASSESSMENT)} // Only valid if coming from flow
          />
        );
      case ScreenName.LEARN:
        return <PlaceholderScreen title="Resource Library" icon="local_library" theme={theme} />;
      case ScreenName.PROFILE:
        return <PlaceholderScreen title="Your Profile" icon="account_circle" theme={theme} />;

      // Details
      case ScreenName.DETAIL:
        const step = PATH_STEPS.find(s => s.id === selectedStepId);
        if (!step) return null;
        return (
          <StepDetailScreen 
            step={step} 
            onBack={() => setCurrentScreen(activeTab)} 
          />
        );
      default:
        return <OnboardingScreen onNext={handleOnboardingComplete} />;
    }
  };

  // Check if we should show the bottom nav
  const showNav = [ScreenName.HOME, ScreenName.PATH, ScreenName.LEARN, ScreenName.PROFILE].includes(currentScreen);
  // Also show Debug Overlay on main screens
  const showDebug = showNav || currentScreen === ScreenName.DETAIL || currentScreen === ScreenName.ASSESSMENT;

  return (
    <Layout theme={theme}>
      {renderScreen()}

      {showNav && (
        <BottomNav 
          currentScreen={currentScreen} 
          onNavigate={handleNav}
          theme={theme}
        />
      )}

      {showDebug && (
        <DebugOverlay 
          currentVersion={uiVersion} 
          onVersionChange={setUiVersion} 
          currentTheme={theme}
          onThemeChange={setTheme}
        />
      )}
    </Layout>
  );
};

export default App;

import React from 'react';
import { Icon } from '../components/Icon';
import { PathStep, Theme } from '../types';
import { PATH_STEPS } from '../data';

interface PathScreenProps {
  onStepClick: (stepId: string) => void;
  onBack: () => void;
  uiVersion?: string; // v1 | v2 | v3
  theme?: Theme;
}

export const PathScreen: React.FC<PathScreenProps> = ({ onStepClick, onBack, uiVersion = 'v1', theme = 'light' }) => {
  const isDark = theme === 'dark';
  const isMinimal = theme === 'minimal';

  // Render based on version
  const renderContent = () => {
    if (uiVersion === 'v2') return <SubwayLayout steps={PATH_STEPS} onStepClick={onStepClick} theme={theme} />;
    if (uiVersion === 'v3') return <FocusCardLayout steps={PATH_STEPS} onStepClick={onStepClick} theme={theme} />;
    return <ClassicLayout steps={PATH_STEPS} onStepClick={onStepClick} theme={theme} />;
  };

  return (
    <div className="flex flex-col h-full relative overflow-hidden">
      {/* Header */}
      <header className={`sticky top-0 z-50 flex items-center p-4 pb-3 justify-between border-b backdrop-blur-md
        ${isDark ? 'bg-slate-900/90 border-slate-800' : 'bg-white/90 border-slate-100'}
        ${isMinimal ? 'bg-white border-black border-b-2' : ''}
      `}>
        {/* Only show back if we have history - simplified for now: Hidden on main tab view */}
        <div className="size-10"></div> 

        <h2 className={`text-sm font-bold leading-tight tracking-tight flex-1 text-center pr-10
          ${isDark ? 'text-white' : 'text-slate-900'}
        `}>
          Marketing <span className={`font-normal mx-1 ${isDark ? 'text-slate-600' : 'text-slate-400'}`}>→</span> PM Journey
        </h2>
      </header>

      <div className="flex-1 flex flex-col p-4 pb-24 overflow-y-auto no-scrollbar">
        <div className="mb-6 mt-2 animate-slide-up">
          <h1 className={`text-2xl font-bold mb-1 ${isDark ? 'text-white' : 'text-slate-900'}`}>Your Transition Route</h1>
          <p className={`text-sm font-medium ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>Estimated timeline: 4-6 months</p>
        </div>

        {/* Start Point Card */}
        <div className="relative z-10 mb-8 animate-slide-up" style={{ animationDelay: '100ms' }}>
          <div className={`rounded-2xl shadow-lg overflow-hidden relative p-6 pb-8
            ${isDark ? 'bg-slate-800 border border-slate-700' : 'bg-gradient-to-b from-blue-600 to-slate-900 text-white'}
            ${isMinimal ? 'bg-white border-2 border-black text-black shadow-none' : ''}
          `}>
            <div className="absolute top-0 right-0 p-4 opacity-10">
              <Icon name="map" className="text-[120px]" />
            </div>

            <div className={`absolute top-4 right-4 backdrop-blur-md px-3 py-1 rounded-full border
              ${isMinimal ? 'border-black bg-white text-black' : 'bg-white/20 border-white/10'}
            `}>
              <span className="text-[10px] font-bold tracking-wider uppercase">Start Point</span>
            </div>

            <div className="relative z-10">
              <div className="flex items-center gap-3 mb-3">
                <div className={`p-2 rounded-lg backdrop-blur-sm
                   ${isMinimal ? 'bg-black text-white' : 'bg-white/20'}
                `}>
                  <Icon name="foundation" className="text-[24px]" />
                </div>
                <h3 className={`text-xl font-bold leading-tight ${isMinimal || !isDark ? 'text-inherit' : 'text-white'}`}>Transferable Skills</h3>
              </div>
              <p className={`text-sm font-medium leading-relaxed pl-1
                 ${isMinimal ? 'text-slate-600' : 'text-blue-100'}
                 ${isDark ? 'text-slate-400' : ''}
              `}>
                Foundation detected: User Research, Stakeholder Management.
              </p>
            </div>
          </div>
        </div>

        {renderContent()}
      </div>
    </div>
  );
};

// --- Helper Props ---
interface LayoutProps {
  steps: PathStep[];
  onStepClick: (id: string) => void;
  theme: Theme;
}

// --- V1: Classic Layout ---
const ClassicLayout: React.FC<LayoutProps> = ({ steps, onStepClick, theme }) => {
  const isDark = theme === 'dark';
  const isMinimal = theme === 'minimal';

  return (
    <div className="relative pl-4 pr-1 animate-fade-in">
      {/* Timeline Line */}
      <div className={`absolute left-[22px] top-0 bottom-0 w-[2px] h-full z-0 
        ${isDark ? 'bg-slate-800' : 'bg-slate-200'}
        ${isMinimal ? 'bg-black' : ''}
      `}></div>
      {/* Active Line Segment */}
      <div className={`absolute left-[22px] top-0 h-[30%] w-[2px] z-0
        ${isMinimal ? 'bg-black' : 'bg-primary'}
      `}></div>

      {steps.map((step, index) => {
        const isCurrent = step.status === 'current';
        const isLocked = step.status === 'locked';

        return (
          <div 
            key={step.id} 
            className="relative z-10 grid grid-cols-[48px_1fr] gap-x-4 mb-8 group animate-slide-up"
            style={{ animationDelay: `${200 + (index * 100)}ms` }}
            onClick={() => !isLocked && onStepClick(step.id)}
          >
            {/* Icon Column */}
            <div className="flex flex-col items-center">
              <div className={`
                flex items-center justify-center size-12 rounded-full z-10 border-4 transition-all duration-300
                ${isDark ? 'border-slate-900' : 'border-[#f6f6f8]'}
                ${isCurrent 
                  ? (isMinimal ? 'bg-black text-white border-black scale-110' : 'bg-primary text-white shadow-glow scale-110') 
                  : ''}
                ${isLocked 
                  ? (isDark ? 'bg-slate-800 text-slate-600' : 'bg-white text-slate-300 border-slate-200') 
                  : ''}
                ${!isCurrent && !isLocked 
                  ? (isMinimal ? 'bg-white text-black border-black' : 'bg-blue-600 text-white') 
                  : ''}
              `}>
                <Icon name={isLocked ? "lock" : isCurrent ? "navigation" : "check"} className={isCurrent ? "animate-pulse" : ""} />
              </div>
            </div>

            {/* Content Column */}
            <div className={`flex flex-col pt-1 pb-2 ${isLocked ? 'opacity-60 grayscale' : 'cursor-pointer hover:scale-[1.01] transition-transform'}`}>
              <div className={`
                rounded-2xl p-5 relative overflow-hidden transition-colors
                ${isDark ? 'bg-slate-800 border-slate-700' : 'bg-white shadow-soft'}
                ${isMinimal ? 'bg-white border-2 border-black shadow-none rounded-none' : 'border'}
                ${isCurrent && !isMinimal ? 'border-primary/20 ring-1 ring-primary/5' : ''}
              `}>
                {isCurrent && (
                  <div className={`absolute -top-3 right-4 text-[10px] font-bold px-3 py-1.5 rounded-full uppercase tracking-wider shadow-sm
                    ${isMinimal ? 'bg-black text-white top-2 right-2' : 'bg-primary text-white'}
                  `}>
                    Current Step
                  </div>
                )}

                <h3 className={`text-lg font-bold leading-tight mb-1
                  ${isDark ? 'text-white' : 'text-slate-900'}
                `}>{step.title}</h3>
                <p className={`text-xs font-semibold uppercase tracking-wide mb-3
                  ${isDark ? 'text-slate-500' : 'text-slate-500'}
                `}>{step.subtitle}</p>

                {/* Chips */}
                <div className="flex gap-2 flex-wrap mb-4">
                  {step.isGap && (
                      <div className={`flex items-center gap-1.5 px-2 py-1 rounded-md border
                        ${isDark ? 'bg-red-900/20 border-red-900/50 text-red-400' : 'bg-red-50 border-red-100 text-red-600'}
                        ${isMinimal ? 'bg-white border-black text-black' : ''}
                      `}>
                        <span className="text-[10px] font-bold uppercase">Gap</span>
                      </div>
                  )}
                    <div className={`flex items-center gap-1.5 px-2 py-1 rounded-md border
                       ${isDark ? 'bg-slate-700 border-slate-600 text-slate-300' : 'bg-slate-50 border-slate-100 text-slate-500'}
                       ${isMinimal ? 'bg-white border-black text-black' : ''}
                    `}>
                      <Icon name="schedule" className="text-[14px]" />
                      <span className="text-[10px] font-bold">{step.effort}</span>
                    </div>
                </div>

                {isCurrent && (
                  <div className={`w-full flex items-center justify-center gap-2 rounded-xl h-12 px-4 text-sm font-bold mt-2 transition-colors
                    ${isMinimal ? 'bg-black text-white hover:bg-slate-800' : 'bg-primary hover:bg-blue-700 active:bg-blue-800 text-white shadow-lg shadow-blue-500/20'}
                  `}>
                    <span>Start Learning</span>
                    <Icon name="arrow_forward" className="text-[18px]" />
                  </div>
                )}
              </div>
            </div>
          </div>
        );
      })}

      {/* End Cap */}
      <div className={`absolute left-[18px] bottom-0 w-3 h-3 rounded-full 
        ${isDark ? 'bg-slate-800' : 'bg-slate-300'}
        ${isMinimal ? 'bg-black' : ''}
      `}></div>
    </div>
  );
};

// --- V2: Subway Layout ---
const SubwayLayout: React.FC<LayoutProps> = ({ steps, onStepClick, theme }) => {
  const isDark = theme === 'dark';
  const isMinimal = theme === 'minimal';

  return (
  <div className="relative pt-4 pb-8 animate-fade-in">
    {/* Center Line */}
    <div className={`absolute left-1/2 top-0 bottom-0 w-1 -translate-x-1/2 rounded-full
      ${isDark ? 'bg-slate-800' : 'bg-slate-200'}
      ${isMinimal ? 'bg-black' : ''}
    `}></div>

    {steps.map((step, index) => {
      const isEven = index % 2 === 0;
      const isCurrent = step.status === 'current';
      const isLocked = step.status === 'locked';

      return (
        <div key={step.id} className="relative mb-8 grid grid-cols-2 gap-8 items-center"
             onClick={() => !isLocked && onStepClick(step.id)}>

           {/* Center Node */}
           <div className={`
             absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 size-5 rounded-full z-20 border-4 transition-all
             ${isDark ? 'border-slate-900' : 'border-[#f6f6f8]'}
             ${isCurrent 
                ? (isMinimal ? 'bg-black scale-125' : 'bg-primary scale-125 ring-4 ring-primary/20') 
                : (isLocked 
                  ? (isDark ? 'bg-slate-700' : 'bg-slate-300') 
                  : (isMinimal ? 'bg-white border-black' : 'bg-blue-600'))}
           `}></div>

           {/* Left Content */}
           <div className={`${!isEven ? 'col-start-1 text-right pr-2' : 'col-start-2 pl-2 order-2'}`}>
             <div className={`
               p-4 rounded-2xl transition-transform
               ${isLocked ? 'opacity-60 grayscale' : 'hover:scale-[1.02] cursor-pointer'}
               ${isDark ? 'bg-slate-800 border-slate-700' : 'bg-white shadow-soft border-slate-100 border'}
               ${isMinimal ? 'bg-white border-2 border-black shadow-none rounded-none' : ''}
               ${isCurrent && !isMinimal ? 'border-primary ring-2 ring-primary/5' : ''}
             `}>
               <h3 className={`font-bold text-sm leading-tight
                 ${isDark ? 'text-white' : 'text-slate-900'}
               `}>{step.title}</h3>
               <p className={`text-[10px] font-medium mt-1
                  ${isDark ? 'text-slate-400' : 'text-slate-500'}
               `}>{step.effort}</p>
               {isCurrent && <div className={`mt-2 text-[10px] font-bold uppercase tracking-wider
                 ${isMinimal ? 'text-black' : 'text-primary'}
               `}>Current</div>}
             </div>
           </div>

           {/* Empty side for balance */}
           <div className={!isEven ? 'col-start-2' : 'col-start-1'}></div>
        </div>
      )
    })}
  </div>
  );
};

// --- V3: Focus Cards Layout ---
const FocusCardLayout: React.FC<LayoutProps> = ({ steps, onStepClick, theme }) => {
  const isDark = theme === 'dark';
  const isMinimal = theme === 'minimal';

  return (
  <div className="flex flex-col gap-4 animate-fade-in">
    {steps.map((step, index) => {
      const isCurrent = step.status === 'current';
      const isLocked = step.status === 'locked';

      return (
        <div 
          key={step.id}
          onClick={() => !isLocked && onStepClick(step.id)}
          className={`
            relative p-6 rounded-3xl transition-all duration-300 border
            ${isCurrent 
              ? (isMinimal ? 'bg-black text-white border-black' : 'bg-slate-900 text-white shadow-xl scale-[1.02] border-transparent') 
              : (isDark 
                  ? 'bg-slate-800 text-slate-200 border-slate-700' 
                  : (isMinimal ? 'bg-white text-black border-2 border-black' : 'bg-white text-slate-900 shadow-soft border-slate-100'))}
            ${isLocked ? 'opacity-50' : 'cursor-pointer hover:shadow-md'}
          `}
        >
          <div className="flex justify-between items-start mb-4">
            <span className={`text-4xl font-black 
               ${isCurrent ? 'text-slate-700' : (isDark ? 'text-slate-700' : 'text-slate-100')}
            `}>
              0{index + 1}
            </span>
            {isCurrent && <Icon name="play_circle" className="text-white text-[32px]" fill />}
            {!isCurrent && !isLocked && <Icon name="check_circle" className="text-green-500 text-[24px]" fill />}
            {isLocked && <Icon name="lock" className="text-slate-300 text-[24px]" />}
          </div>

          <h3 className="text-xl font-bold mb-1">{step.title}</h3>
          <p className={`text-sm font-medium
            ${isCurrent ? 'text-slate-400' : 'text-slate-500'}
          `}>{step.subtitle}</p>

          <div className="mt-4 flex gap-2">
             <span className={`text-[10px] font-bold uppercase tracking-wider px-2 py-1 rounded
               ${isCurrent ? 'bg-slate-800 text-slate-300' : 'bg-slate-100 text-slate-500'}
               ${isDark && !isCurrent ? 'bg-slate-700 text-slate-400' : ''}
               ${isMinimal ? 'bg-white border border-black text-black' : ''}
             `}>
               {step.effort}
             </span>
          </div>
        </div>
      );
    })}
  </div>
  );
};

export enum ScreenName {
  HOME = 'HOME', // Career Coordinates
  PROGRESS = 'PROGRESS', // Skill Gap / Assessment
  LEARN = 'LEARN', // Path / Curriculum
  PROFILE = 'PROFILE',
  DETAIL = 'DETAIL'
}

export type Theme = 'light' | 'dark' | 'minimal';

export interface UserProfile {
  currentRole: string;
  targetRole: string;
  experienceYears: number;
}

export enum SkillStatus {
  TRANSFERABLE = 'TRANSFERABLE',
  GAP = 'GAP'
}

export enum SkillLevel {
  NONE = 'None',
  BASIC = 'Basic',
  EXPERT = 'Expert'
}

export interface Skill {
  id: string;
  name: string;
  description: string;
  status: SkillStatus;
  level: SkillLevel;
  isTransferable: boolean;
}

export interface PathStep {
  id: string;
  title: string;
  subtitle: string;
  description: string;
  status: 'completed' | 'current' | 'locked';
  effort: string;
  isGap: boolean;
  resources: Resource[];
  proof?: Proof;
}

export interface Resource {
  type: 'VIDEO' | 'ARTICLE' | 'TEMPLATE';
  title: string;
  author?: string;
  url: string;
}

export interface Proof {
  authorName: string;
  authorRole: string;
  authorCompany: string;
  authorImage: string;
  quote: string;
}

import React from 'react';
import { Icon } from './Icon';
import { ScreenName, Theme } from '../types';

interface BottomNavProps {
  currentScreen: ScreenName;
  onNavigate: (screen: ScreenName) => void;
  theme: Theme;
}

export const BottomNav: React.FC<BottomNavProps> = ({ currentScreen, onNavigate, theme }) => {

  const navItems = [
    { id: ScreenName.HOME, icon: 'my_location', label: 'Home' },
    { id: ScreenName.PROGRESS, icon: 'analytics', label: 'Progress' },
    { id: ScreenName.LEARN, icon: 'school', label: 'Learn' },
    { id: ScreenName.PROFILE, icon: 'person', label: 'Profile' },
  ];

  const isDark = theme === 'dark';
  const isMinimal = theme === 'minimal';

  return (
    <div className={`fixed bottom-0 left-0 right-0 max-w-md mx-auto z-40 flex justify-around items-center h-20 pb-4 border-t transition-colors duration-300
      ${isDark ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}
      ${isMinimal ? 'bg-white border-t-2 border-black' : ''}
    `}>
      {navItems.map((item) => {
        // Active state logic: If current screen is Detail, it doesn't highlight any nav item, or we could highlight 'Learn' if we knew parent. 
        // For simplicity, strict equality.
        const isActive = currentScreen === item.id;

        let activeColor = 'text-primary';
        if (isDark) activeColor = 'text-blue-400';
        if (isMinimal) activeColor = 'text-black';

        let inactiveColor = 'text-slate-400';
        if (isDark) inactiveColor = 'text-slate-600';
        if (isMinimal) inactiveColor = 'text-gray-400';

        return (
          <button 
            key={item.id}
            onClick={() => onNavigate(item.id)}
            className={`flex flex-col items-center gap-1 w-16 transition-colors ${isActive ? activeColor : inactiveColor}`}
          >
            <Icon 
              name={item.icon} 
              fill={isActive && !isMinimal} 
              className={`text-[26px] transition-transform duration-200 ${isActive ? 'scale-110' : ''}`}
            />
            <span className="text-[10px] font-bold tracking-wide">{item.label}</span>

            {/* Active Indicator Dot */}
            <div className={`size-1 rounded-full mt-0.5 transition-all duration-300 ${isActive ? (isMinimal ? 'bg-black' : 'bg-current') : 'bg-transparent scale-0'}`}></div>
          </button>
        );
      })}
    </div>
  );
};

import React, { useState } from 'react';
import { Icon } from '../components/Icon';
import { UserProfile, Skill, SkillLevel } from '../types';
import { INITIAL_SKILLS } from '../data';

interface AssessmentScreenProps {
  userProfile: UserProfile;
  onNext: () => void;
}

export const AssessmentScreen: React.FC<AssessmentScreenProps> = ({ userProfile, onNext }) => {
  const [skills, setSkills] = useState<Skill[]>(INITIAL_SKILLS);

  // Calculate progress
  const progress = 35; // Mock progress for visual

  const handleLevelChange = (id: string, level: SkillLevel) => {
    setSkills(prev => prev.map(s => s.id === id ? { ...s, level } : s));
  };

  return (
    <div className="flex flex-col h-full bg-[#f6f6f8]">
      {/* Header */}
      <div className="sticky top-0 z-30 bg-white/90 backdrop-blur-md border-b border-slate-100">
        <div className="flex items-center justify-center px-4 py-3">
          <h2 className="text-xs font-bold tracking-widest text-slate-400 uppercase">Skill Gap Assessment</h2>
        </div>
        {/* Progress Bar */}
        <div className="w-full h-1 bg-slate-100">
          <div className="h-full bg-primary rounded-r-full transition-all duration-500 ease-out" style={{ width: `${progress}%` }}></div>
        </div>
      </div>

      <div className="flex-1 px-4 pt-6 pb-28 overflow-y-auto">
        {/* Context Chip */}
        <div className="inline-flex items-center gap-2 px-3 py-1.5 rounded-full bg-blue-50 border border-blue-100 mb-4 animate-fade-in">
          <Icon name="swap_horiz" className="text-primary text-[18px]" />
          <span className="text-primary text-xs font-bold tracking-wide">
            {userProfile.currentRole || 'Marketing'} → {userProfile.targetRole || 'Product Manager'}
          </span>
        </div>

        <h1 className="text-3xl font-bold tracking-tight text-slate-900 mb-2">Check your toolkit</h1>
        <p className="text-slate-500 text-sm leading-relaxed mb-8">
          Update your comfort level with these core {userProfile.targetRole} skills.
        </p>

        <div className="flex flex-col gap-4">
          {skills.map((skill, index) => (
            <div 
              key={skill.id} 
              className="bg-white rounded-2xl p-5 shadow-soft border border-transparent transition-all animate-slide-up"
              style={{ animationDelay: `${index * 50}ms` }}
            >
              <div className="flex justify-between items-start mb-4">
                <div>
                  <h3 className="font-bold text-lg text-slate-900">{skill.name}</h3>
                  <p className="text-xs text-slate-500 mt-1 font-medium">{skill.description}</p>
                </div>
                {skill.isTransferable && (
                  <div className="flex items-center gap-1 bg-green-50 text-green-700 px-2 py-1 rounded-md border border-green-100">
                    <Icon name="check_circle" className="text-[14px]" fill />
                    <span className="text-[10px] font-bold uppercase tracking-wider">Transferable</span>
                  </div>
                )}
              </div>

              {/* Toggle Switch */}
              <div className="grid grid-cols-3 gap-1 bg-slate-100 p-1 rounded-xl">
                {[SkillLevel.NONE, SkillLevel.BASIC, SkillLevel.EXPERT].map((level) => {
                  const isActive = skill.level === level;
                  return (
                    <button
                      key={level}
                      onClick={() => handleLevelChange(skill.id, level)}
                      className={`py-2.5 text-sm font-semibold rounded-lg transition-all duration-200 ${
                        isActive 
                          ? 'bg-white text-primary shadow-sm ring-1 ring-black/5' 
                          : 'text-slate-500 hover:text-slate-700 hover:bg-slate-200/50'
                      }`}
                    >
                      {level}
                    </button>
                  );
                })}
              </div>
            </div>
          ))}
        </div>

        <p className="mt-8 text-center text-xs text-slate-400 max-w-xs mx-auto">
          Accurate self-assessment helps us curate better learning resources for you.
        </p>
      </div>

       {/* Sticky Bottom CTA */}
      <div className="fixed bottom-20 left-0 right-0 p-4 z-20 pointer-events-none">
        <div className="max-w-md mx-auto pointer-events-auto">
             <button 
              onClick={onNext}
              className="w-full bg-primary hover:bg-blue-700 text-white font-bold h-14 rounded-xl shadow-lg shadow-primary/25 active:scale-[0.98] transition-all flex items-center justify-center gap-2 group"
            >
              Update Learning Plan
              <Icon name="arrow_forward" className="group-hover:translate-x-1 transition-transform" />
            </button>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Icon } from '../components/Icon';
import { PathStep, Theme } from '../types';
import { PATH_STEPS } from '../data';

interface PathScreenProps {
  onStepClick: (stepId: string) => void;
  uiVersion?: string; // v1 | v2 | v3
  theme?: Theme;
}

export const PathScreen: React.FC<PathScreenProps> = ({ onStepClick, uiVersion = 'v1', theme = 'light' }) => {
  const isDark = theme === 'dark';
  const isMinimal = theme === 'minimal';

  // Render based on version
  const renderContent = () => {
    if (uiVersion === 'v2') return <SubwayLayout steps={PATH_STEPS} onStepClick={onStepClick} theme={theme} />;
    if (uiVersion === 'v3') return <FocusCardLayout steps={PATH_STEPS} onStepClick={onStepClick} theme={theme} />;
    return <ClassicLayout steps={PATH_STEPS} onStepClick={onStepClick} theme={theme} />;
  };

  return (
    <div className="flex flex-col h-full relative overflow-hidden">
      {/* Header */}
      <header className={`sticky top-0 z-50 flex items-center p-4 pb-3 justify-center border-b backdrop-blur-md
        ${isDark ? 'bg-slate-900/90 border-slate-800' : 'bg-white/90 border-slate-100'}
        ${isMinimal ? 'bg-white border-black border-b-2' : ''}
      `}>
        <h2 className={`text-sm font-bold leading-tight tracking-tight text-center
          ${isDark ? 'text-white' : 'text-slate-900'}
        `}>
          Learning Curriculum
        </h2>
      </header>

      <div className="flex-1 flex flex-col p-4 pb-24 overflow-y-auto no-scrollbar">
        <div className="mb-6 mt-2 animate-slide-up">
          <h1 className={`text-2xl font-bold mb-1 ${isDark ? 'text-white' : 'text-slate-900'}`}>Your Transition Route</h1>
          <p className={`text-sm font-medium ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>Estimated timeline: 4-6 months</p>
        </div>

        {/* Start Point Card */}
        <div className="relative z-10 mb-8 animate-slide-up" style={{ animationDelay: '100ms' }}>
          <div className={`rounded-2xl shadow-lg overflow-hidden relative p-6 pb-8
            ${isDark ? 'bg-slate-800 border border-slate-700' : 'bg-gradient-to-b from-blue-600 to-slate-900 text-white'}
            ${isMinimal ? 'bg-white border-2 border-black text-black shadow-none' : ''}
          `}>
            <div className="absolute top-0 right-0 p-4 opacity-10">
              <Icon name="map" className="text-[120px]" />
            </div>

            <div className={`absolute top-4 right-4 backdrop-blur-md px-3 py-1 rounded-full border
              ${isMinimal ? 'border-black bg-white text-black' : 'bg-white/20 border-white/10'}
            `}>
              <span className="text-[10px] font-bold tracking-wider uppercase">Start Point</span>
            </div>

            <div className="relative z-10">
              <div className="flex items-center gap-3 mb-3">
                <div className={`p-2 rounded-lg backdrop-blur-sm
                   ${isMinimal ? 'bg-black text-white' : 'bg-white/20'}
                `}>
                  <Icon name="foundation" className="text-[24px]" />
                </div>
                <h3 className={`text-xl font-bold leading-tight ${isMinimal || !isDark ? 'text-inherit' : 'text-white'}`}>Transferable Skills</h3>
              </div>
              <p className={`text-sm font-medium leading-relaxed pl-1
                 ${isMinimal ? 'text-slate-600' : 'text-blue-100'}
                 ${isDark ? 'text-slate-400' : ''}
              `}>
                Foundation detected: User Research, Stakeholder Management.
              </p>
            </div>
          </div>
        </div>

        {renderContent()}
      </div>
    </div>
  );
};

// --- Helper Props ---
interface LayoutProps {
  steps: PathStep[];
  onStepClick: (id: string) => void;
  theme: Theme;
}

// --- V1: Classic Layout ---
const ClassicLayout: React.FC<LayoutProps> = ({ steps, onStepClick, theme }) => {
  const isDark = theme === 'dark';
  const isMinimal = theme === 'minimal';

  return (
    <div className="relative pl-4 pr-1 animate-fade-in">
      {/* Timeline Line */}
      <div className={`absolute left-[22px] top-0 bottom-0 w-[2px] h-full z-0 
        ${isDark ? 'bg-slate-800' : 'bg-slate-200'}
        ${isMinimal ? 'bg-black' : ''}
      `}></div>
      {/* Active Line Segment */}
      <div className={`absolute left-[22px] top-0 h-[30%] w-[2px] z-0
        ${isMinimal ? 'bg-black' : 'bg-primary'}
      `}></div>

      {steps.map((step, index) => {
        const isCurrent = step.status === 'current';
        const isLocked = step.status === 'locked';

        return (
          <div 
            key={step.id} 
            className="relative z-10 grid grid-cols-[48px_1fr] gap-x-4 mb-8 group animate-slide-up"
            style={{ animationDelay: `${200 + (index * 100)}ms` }}
            onClick={() => !isLocked && onStepClick(step.id)}
          >
            {/* Icon Column */}
            <div className="flex flex-col items-center">
              <div className={`
                flex items-center justify-center size-12 rounded-full z-10 border-4 transition-all duration-300
                ${isDark ? 'border-slate-900' : 'border-[#f6f6f8]'}
                ${isCurrent 
                  ? (isMinimal ? 'bg-black text-white border-black scale-110' : 'bg-primary text-white shadow-glow scale-110') 
                  : ''}
                ${isLocked 
                  ? (isDark ? 'bg-slate-800 text-slate-600' : 'bg-white text-slate-300 border-slate-200') 
                  : ''}
                ${!isCurrent && !isLocked 
                  ? (isMinimal ? 'bg-white text-black border-black' : 'bg-blue-600 text-white') 
                  : ''}
              `}>
                <Icon name={isLocked ? "lock" : isCurrent ? "navigation" : "check"} className={isCurrent ? "animate-pulse" : ""} />
              </div>
            </div>

            {/* Content Column */}
            <div className={`flex flex-col pt-1 pb-2 ${isLocked ? 'opacity-60 grayscale' : 'cursor-pointer hover:scale-[1.01] transition-transform'}`}>
              <div className={`
                rounded-2xl p-5 relative overflow-hidden transition-colors
                ${isDark ? 'bg-slate-800 border-slate-700' : 'bg-white shadow-soft'}
                ${isMinimal ? 'bg-white border-2 border-black shadow-none rounded-none' : 'border'}
                ${isCurrent && !isMinimal ? 'border-primary/20 ring-1 ring-primary/5' : ''}
              `}>
                {isCurrent && (
                  <div className={`absolute -top-3 right-4 text-[10px] font-bold px-3 py-1.5 rounded-full uppercase tracking-wider shadow-sm
                    ${isMinimal ? 'bg-black text-white top-2 right-2' : 'bg-primary text-white'}
                  `}>
                    Current Step
                  </div>
                )}

                <h3 className={`text-lg font-bold leading-tight mb-1
                  ${isDark ? 'text-white' : 'text-slate-900'}
                `}>{step.title}</h3>
                <p className={`text-xs font-semibold uppercase tracking-wide mb-3
                  ${isDark ? 'text-slate-500' : 'text-slate-500'}
                `}>{step.subtitle}</p>

                {/* Chips */}
                <div className="flex gap-2 flex-wrap mb-4">
                  {step.isGap && (
                      <div className={`flex items-center gap-1.5 px-2 py-1 rounded-md border
                        ${isDark ? 'bg-red-900/20 border-red-900/50 text-red-400' : 'bg-red-50 border-red-100 text-red-600'}
                        ${isMinimal ? 'bg-white border-black text-black' : ''}
                      `}>
                        <span className="text-[10px] font-bold uppercase">Gap</span>
                      </div>
                  )}
                    <div className={`flex items-center gap-1.5 px-2 py-1 rounded-md border
                       ${isDark ? 'bg-slate-700 border-slate-600 text-slate-300' : 'bg-slate-50 border-slate-100 text-slate-500'}
                       ${isMinimal ? 'bg-white border-black text-black' : ''}
                    `}>
                      <Icon name="schedule" className="text-[14px]" />
                      <span className="text-[10px] font-bold">{step.effort}</span>
                    </div>
                </div>

                {isCurrent && (
                  <div className={`w-full flex items-center justify-center gap-2 rounded-xl h-12 px-4 text-sm font-bold mt-2 transition-colors
                    ${isMinimal ? 'bg-black text-white hover:bg-slate-800' : 'bg-primary hover:bg-blue-700 active:bg-blue-800 text-white shadow-lg shadow-blue-500/20'}
                  `}>
                    <span>Start Learning</span>
                    <Icon name="arrow_forward" className="text-[18px]" />
                  </div>
                )}
              </div>
            </div>
          </div>
        );
      })}

      {/* End Cap */}
      <div className={`absolute left-[18px] bottom-0 w-3 h-3 rounded-full 
        ${isDark ? 'bg-slate-800' : 'bg-slate-300'}
        ${isMinimal ? 'bg-black' : ''}
      `}></div>
    </div>
  );
};

// --- V2: Subway Layout ---
const SubwayLayout: React.FC<LayoutProps> = ({ steps, onStepClick, theme }) => {
  const isDark = theme === 'dark';
  const isMinimal = theme === 'minimal';

  return (
  <div className="relative pt-4 pb-8 animate-fade-in">
    {/* Center Line */}
    <div className={`absolute left-1/2 top-0 bottom-0 w-1 -translate-x-1/2 rounded-full
      ${isDark ? 'bg-slate-800' : 'bg-slate-200'}
      ${isMinimal ? 'bg-black' : ''}
    `}></div>

    {steps.map((step, index) => {
      const isEven = index % 2 === 0;
      const isCurrent = step.status === 'current';
      const isLocked = step.status === 'locked';

      return (
        <div key={step.id} className="relative mb-8 grid grid-cols-2 gap-8 items-center"
             onClick={() => !isLocked && onStepClick(step.id)}>

           {/* Center Node */}
           <div className={`
             absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 size-5 rounded-full z-20 border-4 transition-all
             ${isDark ? 'border-slate-900' : 'border-[#f6f6f8]'}
             ${isCurrent 
                ? (isMinimal ? 'bg-black scale-125' : 'bg-primary scale-125 ring-4 ring-primary/20') 
                : (isLocked 
                  ? (isDark ? 'bg-slate-700' : 'bg-slate-300') 
                  : (isMinimal ? 'bg-white border-black' : 'bg-blue-600'))}
           `}></div>

           {/* Left Content */}
           <div className={`${!isEven ? 'col-start-1 text-right pr-2' : 'col-start-2 pl-2 order-2'}`}>
             <div className={`
               p-4 rounded-2xl transition-transform
               ${isLocked ? 'opacity-60 grayscale' : 'hover:scale-[1.02] cursor-pointer'}
               ${isDark ? 'bg-slate-800 border-slate-700' : 'bg-white shadow-soft border-slate-100 border'}
               ${isMinimal ? 'bg-white border-2 border-black shadow-none rounded-none' : ''}
               ${isCurrent && !isMinimal ? 'border-primary ring-2 ring-primary/5' : ''}
             `}>
               <h3 className={`font-bold text-sm leading-tight
                 ${isDark ? 'text-white' : 'text-slate-900'}
               `}>{step.title}</h3>
               <p className={`text-[10px] font-medium mt-1
                  ${isDark ? 'text-slate-400' : 'text-slate-500'}
               `}>{step.effort}</p>
               {isCurrent && <div className={`mt-2 text-[10px] font-bold uppercase tracking-wider
                 ${isMinimal ? 'text-black' : 'text-primary'}
               `}>Current</div>}
             </div>
           </div>

           {/* Empty side for balance */}
           <div className={!isEven ? 'col-start-2' : 'col-start-1'}></div>
        </div>
      )
    })}
  </div>
  );
};

// --- V3: Focus Cards Layout ---
const FocusCardLayout: React.FC<LayoutProps> = ({ steps, onStepClick, theme }) => {
  const isDark = theme === 'dark';
  const isMinimal = theme === 'minimal';

  return (
  <div className="flex flex-col gap-4 animate-fade-in">
    {steps.map((step, index) => {
      const isCurrent = step.status === 'current';
      const isLocked = step.status === 'locked';

      return (
        <div 
          key={step.id}
          onClick={() => !isLocked && onStepClick(step.id)}
          className={`
            relative p-6 rounded-3xl transition-all duration-300 border
            ${isCurrent 
              ? (isMinimal ? 'bg-black text-white border-black' : 'bg-slate-900 text-white shadow-xl scale-[1.02] border-transparent') 
              : (isDark 
                  ? 'bg-slate-800 text-slate-200 border-slate-700' 
                  : (isMinimal ? 'bg-white text-black border-2 border-black' : 'bg-white text-slate-900 shadow-soft border-slate-100'))}
            ${isLocked ? 'opacity-50' : 'cursor-pointer hover:shadow-md'}
          `}
        >
          <div className="flex justify-between items-start mb-4">
            <span className={`text-4xl font-black 
               ${isCurrent ? 'text-slate-700' : (isDark ? 'text-slate-700' : 'text-slate-100')}
            `}>
              0{index + 1}
            </span>
            {isCurrent && <Icon name="play_circle" className="text-white text-[32px]" fill />}
            {!isCurrent && !isLocked && <Icon name="check_circle" className="text-green-500 text-[24px]" fill />}
            {isLocked && <Icon name="lock" className="text-slate-300 text-[24px]" />}
          </div>

          <h3 className="text-xl font-bold mb-1">{step.title}</h3>
          <p className={`text-sm font-medium
            ${isCurrent ? 'text-slate-400' : 'text-slate-500'}
          `}>{step.subtitle}</p>

          <div className="mt-4 flex gap-2">
             <span className={`text-[10px] font-bold uppercase tracking-wider px-2 py-1 rounded
               ${isCurrent ? 'bg-slate-800 text-slate-300' : 'bg-slate-100 text-slate-500'}
               ${isDark && !isCurrent ? 'bg-slate-700 text-slate-400' : ''}
               ${isMinimal ? 'bg-white border border-black text-black' : ''}
             `}>
               {step.effort}
             </span>
          </div>
        </div>
      );
    })}
  </div>
  );
};

import React, { useState } from 'react';
import { Layout } from './components/Layout';
import { BottomNav } from './components/BottomNav';
import { OnboardingScreen } from './screens/OnboardingScreen';
